INSERT INTO `topic_nodes` VALUES (1,NULL,1,'Кинематика','kinematics','Раздел механики, изучающий движение тел без рассмотрения причин, вызывающих это движение.','#2eff8c','2026-05-31 15:06:26','2026-06-11 20:49:40','mechanics'),(2,NULL,2,'Динамика','dynamics','Раздел механики, изучающий причины движения тел.','#ffcb3d','2026-05-31 15:06:26','2026-06-01 07:23:07','mechanics'),(3,NULL,3,'Законы сохранения','conservation','Фундаментальные законы: сохранение импульса, энергии, момента импульса.','#01acff','2026-05-31 15:06:26','2026-06-14 01:00:59','mechanics'),(4,NULL,4,'Статика и гидростатика','statics','Условия равновесия, давление, закон Архимеда.','#ff6b6b','2026-05-31 15:06:26','2026-06-01 07:23:07','mechanics'),(5,NULL,5,'Молекулярная физика','molecular','Основы МКТ, идеальный газ, термодинамические процессы.','#ff8c42','2026-05-31 15:06:26','2026-06-01 07:23:07','molecular-thermodynamics'),(6,NULL,6,'Электростатика','electrostatics','Закон Кулона, электрическое поле, потенциал, ёмкость.','#a78bfa','2026-05-31 15:06:26','2026-06-01 07:23:07','electrodynamics'),(7,NULL,7,'Постоянный ток','dc-circuits','Законы Ома, соединения проводников, работа и мощность тока.','#2eff8c','2026-05-31 15:06:26','2026-06-01 07:23:07','electrodynamics'),(8,NULL,8,'Магнетизм','magnetism','Магнитное поле, сила Ампера, сила Лоренца, электромагнитная индукция.','#ffcb3d','2026-05-31 15:06:26','2026-06-01 07:23:07','electrodynamics'),(9,NULL,9,'Колебания и волны','oscillations','Механические и электромагнитные колебания, гармонические колебания, волны.','#01acff','2026-05-31 15:06:26','2026-06-01 07:23:07',NULL),(10,NULL,10,'Оптика','optics','Закон преломления, линзы, оптические приборы, природа света.','#ff6b6b','2026-05-31 15:06:26','2026-06-01 07:23:07','optics'),(11,NULL,11,'Атомная физика','atomic','Модели атома, спектры, постулаты Бора, радиоактивность.','#ff8c42','2026-05-31 15:06:26','2026-06-01 07:23:07','nuclear-physics'),(12,NULL,12,'Квантовая физика','quantum','Де Бройля, принцип неопределённости, элементы СТО.','#a78bfa','2026-05-31 15:06:26','2026-06-01 07:23:07','nuclear-physics'),(13,1,1,'Равномерное прямолинейное движение','kinematics-sub-1','Равномерное прямолинейное движение — это движение по прямой линии, при котором тело за любые равные промежутки времени совершает одинаковые перемещения. \n\nГлавная фишка: \nскорость постоянна ($v = \\text{const}$)\n\nОсновное уравнение движения (зависимость координаты от времени):\n\n$$x(t) = x_0 + v_x t$$\n\nГде: $x$ — конечная координата $[м]$,\n$x_0$ — начальная координата $[м]$,\n$v_x$ — проекция скорости на ось $X$ $[м/с]$,\n$t$ — время $[с]$\n\nНе путай путь ($s$) и перемещение ($\\Delta x$). \nПри движении в одну сторону по прямой они равны, но если тело развернулось, то путь растет, а перемещение может уменьшаться. \n\nДля РПД без разворотов: $s = v \\cdot t$.\n\n### **График скорости $v(t)$**\n\nЭто всегда горизонтальная прямая. \n\n💡 Лайфхак «Площадь»: Площадь фигуры под графиком скорости $v(t)$ численно равна пройденному пути $s$. \n\nДля РПД это просто прямоугольник: $S = v \\cdot t$. \n\n\n\n\n### **График координаты $x(t)$**\n\nЭто всегда прямая линия (наклонная).\n\n💡 Лайфхак «Тангенс»: Чем круче график идет вверх, тем больше скорость. \n\nСкорость — это тангенс угла наклона графика к оси времени: $v = \\tan(\\alpha)$.\n> Если график идет вверх ($\\alpha < 90^\\circ$) $\\rightarrow v > 0$ (тело движется по оси $X$).\n\n> Если график идет вниз ($\\alpha > 90^\\circ$) $\\rightarrow v < 0$ (тело движется против оси $X$).\n\n> Если график параллелен оси времени $\\rightarrow v = 0$ (тело стоит на месте).','#2eff8c','2026-05-31 15:06:26','2026-06-13 20:56:47',NULL),(14,1,2,'Равноускоренное движение','kinematics-sub-2','При равноускоренном движении ускорение постоянно: $a = \\text{const}$.\n\nОсновные формулы:\n- $v = v_0 + at$\n- $s = v_0t + \\frac{at^2}{2}$\n- $v^2 - v_0^2 = 2as$\n\nГрафик скорости от времени — наклонная прямая.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(15,1,3,'Движение по окружности','kinematics-sub-3','Особенности движения по окружности с\nпостоянной по модулю скоростью:\n\n> Траектория движения тела есть окружность.\n\n\n> Вектор скорости всегда направлен по касательной к окружности.\n\n> Направление скорости постоянно меняется под действием центростремительного ускорения.\n\n> Центростремительное ускорение направлено к центру окружности и не вызывает изменения модуля скорости.\n\n\n\nЦентростремительное ускорение:\n$$a = \\frac{v^2}{R} = \\omega^2 R$$\n\nПериод: $T = \\frac{2\\pi R}{v}$\n\nЧастота: $\\nu = \\frac{1}{T}$\n\nУгловая скорость: $\\omega = \\frac{2\\pi}{T}$','#2eff8c','2026-05-31 15:06:26','2026-06-13 20:27:42',NULL),(16,1,4,'Относительность движения','kinematics-sub-4','Скорость тела относительно **неподвижной** системы отсчёта равна векторной сумме скорости тела относительно **подвижной** системы и скорости **подвижной** системы относительно **неподвижной**:\n\n$$\\vec{v} = \\vec{v}\\ + \\vec{v}_0$$\n\n\n![kinematics-sub-4_p1.png](/uploads/1781410980286-7pokrlq3vdi.png)\n','#2eff8c','2026-05-31 15:06:26','2026-06-13 20:24:11',NULL),(17,2,1,'Законы Ньютона','dynamics-sub-1','Все законы Ньютона выполняются только в инерциальных системах отсчета (ИСО). \n\n> Система отсчета называется инерциальной, если в ней изолированное тело движется равномерно и прямолинейно или покоится.\n\n**I закон:**\nСуществуют такие системы отсчета, называемые инерциальными, относительно которых материальная точка при отсутствии внешних воздействий (или при их взаимной компенсации) сохраняет состояние покоя или равномерного прямолинейного движения.\n\n\n> Математическое условие:\n> $$\\text{Если } \\vec{F}_{\\text{равн}} = \\sum \\vec{F}_i = 0 \\implies \\vec{v} = \\text{const} \\ (\\vec{a} = 0)$$\n \n\n💡 Шпаргалка-триггер для ОГЭ/ЕГЭ: Если в тексте задачи сказано: «тело движется равномерно», «скорость постоянна», «коробка покоится на плоскости», должен мгновенно срабатывать триггер: Равнодействующая сил равна нулю!\n\n\n⚠️ Осторожно, ловушка! \n\nВ ИСО не существует «силы инерции». Если автобус резко тормозит, и пассажир падает вперед, на него не действует сила, толкающая вперед. Он движется вперед по первому закону Ньютона, стремясь сохранить свою скорость относительно Земли, пока автобус замедляется. За рисование сил инерции на бланке ЕГЭ выставляют 0 баллов за рисунок.\n\n**II закон:**  В инерциальной системе отсчета ускорение, приобретаемое материальной точкой, прямо пропорционально равнодействующей всех приложенных к ней сил и обратно пропорционально ее массе.\n\n> Векторный вид:\n> $$\\vec{F}_{\\text{равн}} = m\\vec{a} \\quad \\implies \\quad \\sum_{i=1}^{n} \\vec{F}_i = m\\vec{a}$$\n\n> Дифференциальная форма (Олимпиадный уровень через импульс):\n> $$\\vec{F} = \\frac{d\\vec{p}}{dt}$$\n\n\n**Метод проекций**\n\n1.  Выполнить качественный рисунок. \n2.  Изобразить тело изолированно от других.Расставить все действующие на тело силы (тяжести, реакции опоры, трения, натяжения нити и т.д.).\n3.  Изобразить вектор ускорения $\\vec{a}$ рядом с телом.\n4.  Записать II закон Ньютона в векторном виде: \n$\\vec{F}_1 + \\vec{F}_2 + \\dots + \\vec{F}_n = m\\vec{a}$.\n5.  Спроецировать уравнение на оси координат: \n\nПо оси $Ox$: $F_{1x} + F_{2x} + \\dots = ma$\n\nПо оси $Oy$: $F_{1y} + F_{2y} + \\dots = 0$ (так как движения вдоль оси $Oy$ нет).\n\n\n\n💡Алгоритмический лайфхак (Метод проекций, «Золотое правило» расстановки сил):\n\nНаправлять одну из осей координат ($Оx$ или $Оy$) всегда по направлению ускорения тела. Тогда по этой оси будет $F = ma$, а по перпендикулярной — $F = 0$. Это экономит кучу времени на ОГЭ и ЕГЭ и минимизирует ошибки со знаками.\nЕсли тело покоится или движется равномерно, оси можно направлять куда угодно, но выгоднее — вдоль плоскости движения.\n\n\n**III закон:** сила действия равна по модулю и противоположна по направлению силе противодействия.\n\n\nМатериальные точки взаимодействуют друг со другом силами, имеющими одинаковую физическую природу, равными по модулю и противоположными по направлению.\n\n> Математический вид: $$\\vec{F}_{12} = -\\vec{F}_{21}$$\n\n\n🏆 Для олимпиадников (Разбор парадокса): \n\n«Если сила действия равна силе противодействия, то почему конь может сдвинуть телегу с места? Ведь они тянут друг друга с одинаковой силой!»\n\nОтвет: Силы из третьего закона Ньютона приложены к разным телам, поэтому они никогда не могут уравновесить друг друга. Чтобы понять, почему конь движется, нужно рассматривать силы, действующие только на коня: это сила трения покоя его копыт о землю $\\vec{F}_{\\text{тр}}$ (направлена вперед) и сила натяжения упряжи $\\vec{F}_{\\text{упр}}$ со стороны телеги (направлена назад). Движение начнется, как только $F_{\\text{тр}} > F_{\\text{упр}}$.\n\n\n','#2eff8c','2026-05-31 15:06:26','2026-06-13 23:39:25',NULL),(20,3,1,'Импульс тела','conservation-sub-1','Импульс тела (количество движения) — это векторная физическая величина, равная произведению массы тела на его скорость. \n\nВектор импульса всегда сонаправлен с вектором скорости.\n\nЕдиница измерения в СИ: кг·м/с. \nФормула:$$p⃗ = m · v⃗$$. В проекции на ось координат (например, Ox): $$p_x = m · v_x$$\n\nИмпульс силы — векторная физическая величина, равная произведению средней силы на время ее действия. \n\nХарактеризует меру воздействия силы на тело за данный промежуток времени. \nЕдиница измерения в СИ: Н·с.\n\nФормула:$$ I⃗ = F⃗_{ср} · Δt$$\n\nВторой закон Ньютона в импульсной форме: Изменение импульса тела равно импульсу действующей на него силы (или равнодействующей всех сил):\n\n$$Δp⃗ = F⃗ · Δt \\implies m·v⃗ - m·v⃗_0 = F⃗ · Δt$$\n\n💡  Лайфхак \"Площадь\": Геометрический смысл импульса силы (Графики):\n\nЕсли в условии задачи (часто в первой части ЕГЭ и ОГЭ) дан график зависимости силы $F$ от времени $t$, то изменение импульса тела численно равно площади фигуры под графиком на заданном промежутке времени. Не нужно искать промежуточное ускорение, если можно просто посчитать площадь треугольника или трапеции.\n\n⚠️ Подводный камень №2: Изменение импульса при отскоке (Ловушка проекций)\n\nКлассическая задача: шарик массой $m$ летит со скоростью $v$ перпендикулярно стене, ударяется и абсолютно упруго отскакивает назад с той же скоростью. Чему равен модуль изменения импульса $|\\Delta p|$?Ошибочный ответ учеников: $0$ (думают, что $mv - mv = 0$).Правильное решение: Направляем ось Ox вдоль начального движения. Тогда $p_{1x} = mv$, а после отскока $p_{2x} = -mv$. Изменение импульса: $\\Delta p_x = p_{2x} - p_{1x} = -mv - mv = -2mv$. Модуль изменения равен $2mv$.\n\n\n🏆 Олимпиадный финт №3: Системы с переменной массой (Струя воды)\n\nВ сложных задачах (задание №26 в ЕГЭ или олимпиады) встречается удар струи жидкости о стену. Используйте импульсную форму закона Ньютона, выраженную через секундный расход массы: $F = \\frac{\\Delta m}{\\Delta t} · v$. Учитывая, что расход $\\frac{\\Delta m}{\\Delta t} = \\rho \\cdot S \\cdot v$ (где $\\rho$ — плотность, $S$ — площадь сечения струи), получаем силу давления струи при полной остановке:$$F = \\rho · S · v^2$$','#2eff8c','2026-05-31 15:06:26','2026-06-14 00:38:16',NULL),(21,3,2,'Закон сохранения импульса','conservation-sub-2','Замкнутая (изолированная) система — система тел, на которую не действуют внешние силы, или их действие взаимно скомпенсировано $\\sum F⃗_{внеш} = 0$.\n\nЗакон сохранения импульса: В замкнутой системе тел векторная сумма импульсов всех тел остается постоянной при любых взаимодействиях между ними:\n\n$$\\vec{p}_1 + \\vec{p}_2 + ... + \\vec{p}_n = \\text{const}$$\n\n\nДля системы двух взаимодействующих тел:$$m_1 v⃗_1 + m_2 v⃗_2 = m_1 v⃗\'_1 + m_2 v⃗\'_2$$\n\n**Типы соударений:**\n\nАбсолютно упругий удар — сохраняется как импульс, так и кинетическая энергия системы. Тела после удара разлетаются.\n\nАбсолютно неупругий удар — тела соединяются и движутся дальше как единое целое с общей скоростью. Импульс сохраняется, но часть механической энергии переходит во внутреннюю (выделяется тепло $Q$).$$m_1 v⃗_1 + m_2 v⃗_2 = (m_1 + m_2) v⃗_{общ}$$\n\n🔥 Лайфхак: Проекционный ЗСИ (Частичная замкнутость)\n\nБывают ситуации, когда система не замкнута в пространстве (например, действует сила тяжести или сила реакции опоры при выстреле из пушки под углом), но вдоль одной конкретной оси (например, горизонтальной Ox) никакие внешние силы не действуют. ЗСИ отлично работает в проекции на эту конкретную ось!\n\n\n⚠️ Подводный камень №5: Относительная скорость (Выстрелы/Прыжки)\n\nВ задачах типа «человек прыгает с движущейся тележки со скоростью $u$ относительно тележки» неправильно писать в ЗСИ просто скорость $u$.\nПравило: Все скорости в формуле ЗСИ должны быть указаны относительно Земли (в лабораторной системе отсчета). Пересчитывайте скорость через векторное сложение: $v_{чел} = v_{тел} + u$.','#2eff8c','2026-05-31 15:06:26','2026-06-14 00:43:26',NULL),(22,3,3,'Механическая работа и мощность','conservation-sub-3','Механическая работа ($A$) — скалярная величина, равная произведению модулей силы и перемещения на косинус угла между ними.\n\n$$A = F · s · \\cos\\alpha$$\n\n> Знаки работы:\n\n> $\\alpha < 90^\\circ \\implies A > 0$ (сила разгоняет тело).\n\n> $\\alpha = 90^\\circ \\implies A = 0$ (сила не совершает работу, например, сила реакции опоры при горизонтальном движении или центростремительная сила).\n\n> $\\alpha > 90^\\circ \\implies A < 0$ (сила тормозит тело, например, сила трения скольжения, где $\\alpha = 180^\\circ$ и $A = -F_{тр} · s$).\n\nМощность ($N$) — скорость совершения работы.\n\nСредняя мощность: $N_{ср} = \\frac{A}{\\Delta t}$\n\nМгновенная мощность:$$N = F · v · \\cos\\alpha$$\n\n🔥 Лайфхак: \nРабота переменной силы\nФормула $A = Fs\\cos\\alpha$ применима только для постоянной силы. \n\nЕсли сила меняется (например, сила упругости пружины $F = kx$), используйте графический метод: работа равна площади фигуры под графиком зависимости силы от координаты $x$. Для пружины площадь треугольника дает: $A = \\frac{k x^2}{2}$.\n\n\n⚠️ Подводный камень: Положительная работа силы трения\n\nНе зазубривайте правило «работа трения всегда отрицательна». Это не так для силы трения покоя. Когда коробка едет на транспортере или человек ускоряется при ходьбе, именно сила трения покоя толкает тело вперед по направлению движения, совершая работу $A > 0$.','#2eff8c','2026-05-31 15:06:26','2026-06-14 00:47:00',NULL),(23,3,4,'Кинетическая и потенциальная энергия','conservation-sub-4','Кинетическая энергия ($E_к$) — скалярная величина, характеризующая энергию движущегося тела.$$E_к = \\frac{m v^2}{2} = \\frac{p^2}{2m}$$Теорема об изменении кинетической энергии: Изменение кинетической энергии тела равно работе всех сил, действующих на него:$$\\Delta E_к = E_{к2} - E_{к1} = A_{всех\\, сил}$$Потенциальная энергия ($E_п$) — энергия взаимодействия тел, определяемая их взаимным расположением.В поле тяжести Земли: $E_п = mgh$ (величина зависит от выбора нулевого уровня!).Для деформированной пружины: $E_п = \\frac{kx^2}{2}$Связь работы консервативных сил и потенциальной энергии:$$A_{конс} = -\\Delta E_п = E_{п1} - E_{п2}$$\n\n🔥 Лайфхак №8: Моментальная связь импульса и энергииВ комбинированных задачах (соударения + последующее движение) используйте формулу $E_к = \\frac{p^2}{2m}$. Она экономит время, позволяя не рассчитывать скорость как промежуточную величину.🏆 Олимпиадный финт №9: Метод Центра МассДля протяженных тел (например, тяжелый канат или цепь, свисающая со стола) потенциальная энергия рассчитывается через координату его центра масс. Для свисающей вертикально однородной цепи длиной $L$ и массой $M$ центр масс находится ровно посередине свисающей части — на глубине $L/2$.','#2eff8c','2026-05-31 15:06:26','2026-06-14 00:47:34',NULL),(24,3,5,'Закон сохранения энергии','conservation-sub-5','В замкнутой системе тел, где действуют только консервативные силы, полная механическая энергия сохраняется:\n$$E = E_k + E_p = \\text{const}$$\n\nПолная механическая энергия ($E$) — сумма кинетической и потенциальной энергий системы: $E = E_к + E_п$.Закон сохранения механической энергии: \n\nВ замкнутой системе тел, где отсутствуют диссипативные силы (нет трения и сопротивления среды), полная механическая энергия остается постоянной:$$E_{к1} + E_{п1} = E_{к2} + E_{п2}$$\n\n> Диссипативные силы — это силы, которые приводят к уменьшению полной механической энергии системы.\n\nЗакон изменения механической энергии: Если в системе действует трение, механическая энергия уменьшается, переходя в теплоту ($Q$):$$\\Delta E = E_2 - E_1 = A_{внеш} + A_{тр} \\implies Q = -A_{тр}$$\n\n🔥 Лайфхак: Энергетический баланс против динамикиЕсли тело движется по сложной траектории (дуги, горки, петли), кинематические формулы и законы Ньютона использовать крайне трудно, так как ускорение постоянно меняется. ЗСЭ «не видит» форму траектории — ему важны только начальное и конечное состояния системы.\n\n🏆 Олимпиадный финт: Условие прохождения «мертвой петли»\n\nПри съезде тела с горки в петлю радиуса $R$, минимальная высота старта $H_{min}$ находится не из условия скорости $v=0$ на вершине (иначе тело просто упадет вниз). На вершине должна сохраняться критическая скорость, удерживающая тело на окружности (условие отрыва $N=0 \\implies v^2 = gR$). Подставляя это в ЗСЭ, получаем знаменитую формулу:$$H_{min} = 2.5R$$\n![conservation-sub-5.png](/uploads/1781428243829-hvgro3aude.png)\n\n\n\n\n','#2eff8c','2026-05-31 15:06:26','2026-06-14 01:15:13',NULL),(25,4,1,'Условия равновесия твёрдого тела','statics-sub-1','Условия равновесия:\n1. Геометрическая сумма всех сил равна нулю\n2. Сумма моментов всех сил относительно любой оси равна нулю\n\nВ отличие от материальной точки, реальное тело под действием внешних сил может не только изменять скорость своего центра масс, но и вращаться.\n\nАбсолютно твёрдое тело — это идеализированная модель, в которой расстояние между любыми двумя точками остаётся строго неизменным в процессе любых взаимодействий.Для полного механического равновесия твёрдого тела необходимы и достаточны два условия:\n\nПервое условие равновесия (поступательное)\n\nВекторная (геометрическая) сумма всех внешних сил, приложенных к телу, должна быть равна нулю. Это исключает появление линейного ускорения:$$\\sum \\vec{F} = \\vec{F}_1 + \\vec{F}_2 + \\dots + \\vec{F}_n = \\vec{0}$$В проекциях на координатные оси декартовой системы:$$\\sum F_x = 0, \\quad \\sum F_y = 0$$\n\n🔥 ЛАЙФХАК ДЛЯ ЕГЭ/ОГЭ: Помните ключевое правило — вес это сила, а не масса! Вес $\\vec{P}$ по определению приложен к опоре или подвесу, а не к самому рассматриваемому телу. В уравнениях первого условия равновесия сил всегда фигурирует сила тяжести тела $m\\vec{g}$ (приложенная к его центру масс) и сила реакции опоры $\\vec{N}$, но никогда не пишите туда вес самого тела.','#2eff8c','2026-05-31 15:06:26','2026-06-14 01:24:45',NULL),(26,4,2,'Момент силы','statics-sub-2','Если линия действия силы не проходит через ось вращения тела, эта сила вызывает вращательный эффект.\n\nЛиния действия силы — прямая, проходящая вдоль вектора силы.\n\nПлечо силы ($d$) — кратчайшее расстояние от оси вращения до линии действия силы (перпендикуляр, опущенный из точки оси на линию действия силы).\n\nМомент силы ($M$) — физическая величина, равная произведению модуля силы на её плечо:$$M = F \\cdot d$$Второе условие равновесия (вращательное)\n\nАлгебраическая сумма моментов всех внешних сил, действующих на тело относительно любой оси вращения, должна быть равна нулю:$$\\sum M = M_1 + M_2 + \\dots + M_n = 0$$\n\nЗнак момента: Силы, стремящиеся повернуть тело против часовой стрелки, обычно создают положительный момент ($+$), а по часовой стрелке — отрицательный ($-$).\n\n\n🏆 ОЛИМПИАДНЫЙ ЛАЙФХАК: Метод виртуальной (плавающей) осиВы имеете право выбрать точку (ось) вращения в абсолютно любом месте пространства (даже вне самого тела), ведь если тело покоится, оно не вращается ни относительно какой точки.\n\nПрименение: Если в задаче на балку действуют две неизвестные силы реакции опор ($\\vec{N}_1$ и $\\vec{N}_2$), выберите ось вращения точно на линии действия силы $\\vec{N}_1$. Тогда плечо этой силы станет равным нулю ($d = 0$), её момент занулится и исчезнет из уравнения, что позволит вам мгновенно найти $\\vec{N}_2$ всего из одного уравнения моментов.','#2eff8c','2026-05-31 15:06:26','2026-06-14 01:25:53',NULL),(27,4,3,'Давление в жидкостях и газах','statics-sub-3','Жидкости и газы, в отличие от твёрдых тел, обладают текучестью, из-за чего не могут выдерживать постоянные сдвиговые напряжения и передают давление иначе.Закон ПаскаляДавление, производимое на жидкость или газ внешними силами, передаётся в любую точку жидкости или газа одинаково по всем направлениям без изменений.$$P = \\frac{F}{S}$$Гидростатическое давлениеСобственное весовое давление столба неподвижной жидкости плотностью $\\rho$ на глубине $h$ под действием силы тяжести рассчитывается по формуле:$$P_г = \\rho \\cdot g \\cdot h$$Полное давление на глубине складывается из атмосферного давления на поверхности и гидростатического: $P_{полн} = P_{атм} + \\rho gh$.⚠️ ЛОВУШКА ОГЭ/ЕГЭ: Гидростатический парадокс!Давление жидкости на дно сосуда зависит исключительно от плотности жидкости $\\rho$ и высоты столба $h$. Оно абсолютно не зависит от формы сосуда и массы налитой жидкости. Если взять три сосуда разной формы (конический, цилиндрический, расширяющийся вверх) с одинаковой площадью дна $S$ и одинаковым уровнем воды $h$, то сила давления на дно $F = P \\cdot S$ во всех трёх сосудах будет одинаковой, несмотря на разный вес воды в них.','#2eff8c','2026-05-31 15:06:26','2026-06-14 01:26:12',NULL),(28,5,1,'Основы МКТ','molecular-sub-1','Базовые понятия и постулаты\nВ основе МКТ лежат три фундаментальных положения:\n1. Все вещества состоят из микрочастиц (молекул, атомов, ионов), разделенных промежутками.\n2. Эти частицы находятся в непрерывном, хаотическом (тепловом) движении.\n3. Частицы взаимодействуют друг с другом силами притяжения и отталкивания, которые имеют электромагнитную природу.\n\n**Идеальный газ** — это физическая модель, в которой:\n* Собственным объемом молекул можно пренебречь по сравнению с объемом сосуда (молекулы — материальные точки).\n* Потенциальной энергией взаимодействия молекул пренебрегают (нет сил межмолекулярного притяжения/отталкивания на расстоянии).\n* Столкновения молекул друг с другом и со стенками сосуда абсолютно упругие.\n\n### 1.2 Формулы и математический аппарат\n\n* **Количество вещества (𝜈):**\n  $$\\nu = \\frac{N}{N_A} = \\frac{m}{M}$$\n  Где $N$ — число молекул, $N_A \\approx 6{,}02 \\cdot 10^{23} \\text{ моль}^{-1}$ — постоянная Авогадро, $m$ — масса газа, $M$ — молярная масса.\n\n* **Масса одной молекулы ($m_0$):**\n  $$m_0 = \\frac{M}{N_A}$$\n\n* **Концентрация частиц ($n$):**\n  $$n = \\frac{N}{V}$$\n\n* **Основное уравнение МКТ идеального газа (три формы записи):**\n  $$p = \\frac{1}{3} m_0 n \\overline{v^2}$$\n  $$p = \\frac{2}{3} n \\overline{E_k}$$\n  $$p = n k T$$\n  Где $p$ — давление, $\\overline{v^2}$ — средний квадрат скорости, $\\overline{E_k}$ — средняя кинетическая энергия поступательного движения молекул, $k \\approx 1{,}38 \\cdot 10^{-23} \\text{ Дж/К}$ — постоянная Больцмана, $T$ — абсолютная температура в Кельвинах ($T = t^\\circ\\text{C} + 273{,}15$).\n\n* **Средняя кинетическая энергия теплового движения молекул:**\n  $$\\overline{E_k} = \\frac{3}{2} k T$$\n\n* **Средняя квадратичная скорость молекул:**\n  $$v_{\\text{кв}} = \\sqrt{\\frac{3kT}{m_0}} = \\sqrt{\\frac{3RT}{M}}$$\n  Где $R = k \\cdot N_A \\approx 8{,}31 \\text{ Дж/(моль}\\cdot\\text{К)}$ — универсальная газовая постоянная.\n\n### 🛑 Ловушки экзаменов & Лайфхаки по МКТ\n1. **«Ловушка Кельвина» (ОГЭ/ЕГЭ):** В формулах МКТ (особенно $p = nkT$ и $\\overline{E_k} = 1{,}5kT$) температура берется **только** в Кельвинах! Если в условии сказано, что температура Цельсия увеличилась в 2 раза (например, с $10^\\circ\\text{C}$ до $20^\\circ\\text{C}$), давление или энергия **НЕ** увеличатся в 2 раза! Переводите в Кельвины: $283\\text{ К} \\to 293\\text{ К}$ (рост всего на ~3.5%).\n2. **Запоминалка скорости (Лайфхак «Три кота»):** Формулу $v_{\\text{кв}} = \\sqrt{\\frac{3RT}{M}}$ ученики путают. Дайте им мнемонику: *«Три кота ($3RT$) делят Мясо ($M$) под корнем»*. Для молекулярной формы $v_{\\text{кв}} = \\sqrt{\\frac{3kT}{m_0}}$: *«Три кота ($3kT$) на одну мышку ($m_0$)»*.\n3. **Физический смысл давления:** Помните, что $p = \\frac{2}{3}n\\overline{E_k}$. Давление зависит *только* от концентрации (как часто бьют) и кинетической энергии (как сильно бьют). Если смешать два газа, их давления складываются (Закон Дальтона): $p_{\\text{общ}} = p_1 + p_2 = (n_1 + n_2)kT$.\n','#2eff8c','2026-05-31 15:06:26','2026-06-14 01:46:37',NULL),(29,5,2,'Уравнение состояния идеального газа','molecular-sub-2','$$pV = \\nu RT$$\n\nгде $\\nu$ — количество вещества, $R = 8.31$ Дж/(моль·К).',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(30,5,3,'Изопроцессы','molecular-sub-3','**Изотермический** ($T=\\text{const}$): $pV = \\text{const}$\n\n**Изобарный** ($p=\\text{const}$): $\\frac{V}{T} = \\text{const}$\n\n**Изохорный** ($V=\\text{const}$): $\\frac{p}{T} = \\text{const}$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(31,5,4,'Первое начало термодинамики','molecular-sub-4','$$\\Delta U = Q - A$$\n\nИзменение внутренней энергии системы равно количеству теплоты, переданному системе, минус работа, совершённая системой.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(32,6,1,'Закон Кулона','electrostatics-sub-1','$$F = k\\frac{|q_1 q_2|}{r^2}$$\n\nгде $k = 9\\cdot10^9$ Н·м²/Кл².',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(33,6,2,'Напряжённость электрического поля','electrostatics-sub-2','$$E = \\frac{F}{q} = k\\frac{|q|}{r^2}$$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(34,6,3,'Потенциал и работа поля','electrostatics-sub-3','Потенциал: $\\varphi = \\frac{W}{q}$\n\nРабота поля: $A = q(\\varphi_1 - \\varphi_2)$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(35,6,4,'Конденсаторы и ёмкость','electrostatics-sub-4','Ёмкость конденсатора: $C = \\frac{q}{U}$\n\nЁмкость плоского конденсатора: $C = \\frac{\\varepsilon\\varepsilon_0 S}{d}$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(36,7,1,'Закон Ома для участка цепи','dc-circuits-sub-1','$$I = \\frac{U}{R}$$\n\nСопротивление проводника: $R = \\rho\\frac{l}{S}$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(37,7,2,'Последовательное и параллельное соединение','dc-circuits-sub-2','**Последовательное:** $R = R_1 + R_2 + ...$\n\n**Параллельное:** $\\frac{1}{R} = \\frac{1}{R_1} + \\frac{1}{R_2} + ...$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(38,7,3,'Работа и мощность тока','dc-circuits-sub-3','$$Q = I^2 Rt$$\n\nМощность: $P = IU = I^2R = \\frac{U^2}{R}$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(39,7,4,'ЭДС и закон Ома для полной цепи','dc-circuits-sub-4','$$I = \\frac{\\varepsilon}{R + r}$$\n\nгде $r$ — внутреннее сопротивление источника.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(40,8,1,'Магнитное поле','magnetism-sub-1','Магнитное поле создаётся движущимися электрическими зарядами. Линии магнитной индукции замкнуты.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(41,8,2,'Сила Ампера и Лоренца','magnetism-sub-2','Сила Ампера: $F = IBl\\sin\\alpha$\n\nСила Лоренца: $F = qvB\\sin\\alpha$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(42,8,3,'Закон электромагнитной индукции','magnetism-sub-3','$$\\varepsilon_i = -\\frac{\\Delta\\Phi}{\\Delta t}$$\n\nМагнитный поток: $\\Phi = BS\\cos\\alpha$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(43,8,4,'Самоиндукция','magnetism-sub-4','$$\\varepsilon_s = -L\\frac{\\Delta I}{\\Delta t}$$\n\nИндуктивность $L$ зависит от геометрии контура.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(44,9,1,'Гармонические колебания','oscillations-sub-1','Уравнение гармонических колебаний:\n$$x = A\\cos(\\omega t + \\varphi_0)$$\n\nПериод математического маятника: $T = 2\\pi\\sqrt{\\frac{l}{g}}$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(45,9,2,'Электромагнитные колебания','oscillations-sub-2','$$T = 2\\pi\\sqrt{LC}$$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(46,9,3,'Механические волны','oscillations-sub-3','$$v = \\lambda\\nu = \\frac{\\lambda}{T}$$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(47,9,4,'Интерференция и дифракция','oscillations-sub-4','Условие максимума: $\\Delta d = m\\lambda$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(48,10,1,'Отражение и преломление света','optics-sub-1','**Закон отражения:** угол падения равен углу отражения\n\n**Закон преломления:** $n_1\\sin\\alpha_1 = n_2\\sin\\alpha_2$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(49,10,2,'Линзы и изображения','optics-sub-2','Формула тонкой линзы:\n$$\\frac{1}{F} = \\frac{1}{d} + \\frac{1}{f}$$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(50,10,3,'Волновая природа света','optics-sub-3','Свет — электромагнитная волна. Интерференция, дифракция, поляризация.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(51,10,4,'Квантовая природа света','optics-sub-4','Энергия фотона: $E = h\\nu$\n\nУравнение Эйнштейна для фотоэффекта:\n$$h\\nu = A_{\\text{вых}} + E_k$$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(52,11,1,'Модели атома','atomic-sub-1','Томсон — «пудинг с изюмом». Резерфорд — планетарная модель. Бор — квантовые постулаты.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(53,11,2,'Постулаты Бора','atomic-sub-2','1. Атом существует в стационарных состояниях\n2. При переходе излучается фотон: $h\\nu = E_m - E_n$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(54,11,3,'Радиоактивность','atomic-sub-3','$\\alpha$ — ядра гелия, $\\beta$ — электроны, $\\gamma$ — ЭМ излучение.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(55,11,4,'Ядерные реакции','atomic-sub-4','Деление и синтез ядер. Энергия связи: $E = \\Delta m c^2$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(56,12,1,'Гипотеза де Бройля','quantum-sub-1','$$\\lambda = \\frac{h}{p} = \\frac{h}{mv}$$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(57,12,2,'Принцип неопределённости','quantum-sub-2','$$\\Delta x \\cdot \\Delta p \\geq \\frac{\\hbar}{2}$$',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(58,12,3,'Основы СТО','quantum-sub-3','Постулаты Эйнштейна. $E = mc^2$ — связь массы и энергии.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(59,12,4,'Фундаментальные взаимодействия','quantum-sub-4','Гравитационное, электромагнитное, сильное, слабое.',NULL,'2026-05-31 15:06:26','2026-05-31 15:06:26',NULL),(61,1,5,'Движение под углом к горизонту','kinematics-sub-5','Это движение в плоскости, поэтому для описания движения необходимо 2 координаты.\n\nСчитаем, что движение происходит вблизи поверхности Земли, поэтому ускорение тела – ускорение свободного падения (a = g).\n','#2eff8c','2026-06-13 11:36:42','2026-06-13 03:39:10',NULL),(63,2,2,'Гравитационные силы. Сила тяжести и Вес','dynamics-sub2','Закон всемирного тяготения: \n\nЛюбые две материальные точки притягиваются друг к другу с силой:\n\n$$F = G \\frac{m_1 m_2}{R^2}$$\n\nгде $G = 6,67 \\cdot 10^{-11} \\text{ Н}\\cdot\\text{м}^2/\\text{кг}^2$ — гравитационная постоянная.\n\nСила тяжести: Сила притяжения тела к планете вблизи ее поверхности.\n\n$$F_{\\text{тяж}} = mg \\quad \\left(g = G\\frac{M_{\\text{Земли}}}{R_{\\text{Земли}}^2}\\right)$$\n\nПриложена строго к центру масс (центру тяжести) самого тела.\n\n\nВес тела ($P$): Сила, с которой тело вследствие притяжения к Земле действует на свою опору или подвес.Приложена к опоре или подвесу (а не к самому телу!).\n![dynamics-sub2.png](/uploads/1781422419994-lmsaynby9ys.png)\n','#2eff8c','2026-06-14 07:21:31','2026-06-13 23:33:53',NULL),(64,2,3,'Электромагнитные силы. Силы упругости и трения.','dynamics-sub-3','Сила упругости. Закон Гука\n\nВозникает при деформации тел. Имеет электромагнитную природу (межмолекулярное отталкивание/притяжение).\n\nЗакон Гука (для малых деформаций): Сила упругости, возникающая при деформации тела, пропорциональна его удлинению и направлена противоположно направлению деформации.\n\n$$F_{\\text{упр}_x} = -k \\cdot x \\quad \\implies \\quad |F_{\\text{упр}}| = k \\cdot \\Delta l$$где $k$ — жесткость тела (пружины) [Н/м], $\\Delta l = |l - l_0|$ — абсолютная деформация (удлинение/сжатие).\n\n\n🚀 Олимпиадные чит-коды со сложными пружинами:Последовательное соединение пружин: (Удлинения пружин складываются, а сила натяжения одинакова). \n\nЖесткость системы уменьшается:$$\\frac{1}{k_{\\text{общ}}} = \\frac{1}{k_1} + \\frac{1}{k_2} \\quad \\implies \\quad k_{\\text{общ}} = \\frac{k_1 k_2}{k_1 + k_2}$$Параллельное соединение пружин: (Деформация одинакова, а силы упругости складываются). \n\nЖесткость системы увеличивается:$$k_{\\text{общ}} = k_1 + k_2$$\n\nРазрезание пружины: Жесткость пружины обратно пропорциональна ее начальной длине ($k \\cdot L = \\text{const}$).\n\nПример: Если пружину жесткостью $k$ разрезать на 3 равные части, жесткость каждой отдельной части станет равной $3k$.\n\n\nСилы трения (Сухое трение)\n\nВозникает в плоскости соприкосновения поверхностей. Направлена против направления относительного движения.\n\nТрение покоя: Действует между телами, когда они неподвижны друг относительно друга.$$0 \\le F_{\\text{тр.пок}} \\le F_{\\text{тр.макс}}$$\n\nВажнейший лайфхак: Трение покоя не имеет жесткой формулы! Оно всегда в точности равно внешней силе, пытающейся сдвинуть тело с места: $F_{\\text{тр.пок}} = F_{\\text{внеш}}$.\n\nТрение скольжения: Действует, когда тела движутся (проскальзывают) друг относительно друга.$$F_{\\text{тр.ск}} = \\mu N$$где $\\mu$ — безразмерный коэффициент трения, $N$ — сила нормальной реакции опоры.\n\n\n⚠️ Осторожно, ловушка ОГЭ/ЕГЭ! Если к бруску массой $m = 2 \\text{ кг}$, лежащему на полу с коэффициентом трения $\\mu = 0,5$, прикладывают горизонтальную силу $F = 4 \\text{ Н}$, какова сила трения? Ошибочное решение: $F_{\\text{тр}} = \\mu mg = 0,5 \\cdot 2 \\cdot 10 = 10 \\text{ Н}$. Получается, что сила трения равна $10 \\text{ Н}$ и брусок под действием силы $4 \\text{ Н}$ полетит назад! \nФизический абсурд.\nПравильное решение: Максимальное трение покоя $F_{\\text{тр.макс}} = \\mu mg = 10 \\text{ Н}$. Так как внешняя сила $F = 4 \\text{ Н} < 10 \\text{ Н}$, тело с места не сдвинется, и сила трения равна силе покоя: $F_{\\text{тр}} = F_{\\text{внеш}} = 4 \\text{ Н}$.','#2eff8c','2026-06-14 07:41:00','2026-06-13 23:44:35',NULL),(65,2,4,'Криволинейное движение. Центростремительная сила','dynamics-sub-4','Когда тело движется по окружности радиуса $R$ с постоянной по модулю скоростью $v$, направление скорости непрерывно меняется. Из-за этого возникает центростремительное ускорение $a_{\\text{цс}}$, направленное строго к центру окружности.$$a_{\\text{цс}} = \\frac{v^2}{R} = \\omega^2 R$$По второму закону Ньютона, наличие ускорения требует наличия силы:$$\\sum \\vec{F} = m\\vec{a}_{\\text{цс}} \\quad \\implies \\quad F_{\\text{равн}} = \\frac{mv^2}{R}$$\n\n\n💡 Концептуальный лайфхак: Напомните ученикам, что «центростремительной силы» как отдельного физического взаимодействия не существует. Это лишь геометрическая «роль», которую выполняет какая-то из реальных сил.Для спутника на орбите роль центростремительной силы играет сила тяжести: $G\\frac{Mm}{R^2} = \\frac{mv^2}{R}$Для машины на повороте — сила трения покоя: $\\mu mg = \\frac{mv^2}{R}$Для грузика на веревке — сила натяжения нити: $T = \\frac{mv^2}{R}$','#2eff8c','2026-06-14 07:45:46','2026-06-14 00:35:08',NULL),(66,2,5,'Олимпиадные методы анализа','1111','','#2eff8c','2026-06-14 07:54:54','2026-06-14 07:54:54',NULL),(67,4,4,'Сила Архимеда','statics-sub-4','На любое тело, погружённое в жидкость (или газ), действует выталкивающая сила, направленная вертикально вверх и равная весу вытесненной им жидкости:\n\n$$F_А = \\rho_ж \\cdot g \\cdot V_{погр}$$\n\nГде $V_{погр}$ — объём только той части тела, которая фактически находится ниже уровня жидкости.\n\nУсловия плавания тел (анализ плотностей):\n\n> $\\rho_{тела} > \\rho_{жидкости}$ — тело тонет (\n$F_А < F_{тяж}$)\n\n>$\\rho_{тела} = \\rho_{жидкости}$ — тело плавает на любой глубине внутри жидкости (безразличное равновесие)\n\n>$\\rho_{тела} < \\rho_{жидкости}$ — тело всплывает. \n\nПри достижении поверхности часть тела выходит наружу, и устанавливается равновесие плавания: $F_А = F_{тяж} \\Rightarrow \\rho_ж \\cdot g \\cdot V_{погр} = \\rho_т \\cdot g \\cdot V_{тела}$.\n\n🏆 ОЛИМПИАДНЫЙ ЛАЙФХАК: Быстрое отношение объёмов при плавании\n\nДля любого тела, свободно плавающего на поверхности жидкости, справедливо строгое пропорциональное соотношение погружённой доли его объёма к полному объёму:$$\\frac{V_{погр}}{V_{тела}} = \\frac{\\rho_{тела}}{\\rho_{жидкости}}$$\n\nПример: Если айсберг ($\\rho_{льда} = 900 \\, \\text{кг/м}^3$) плавает в океане ($\\rho_{воды} = 1000 \\, \\text{кг/м}^3$), то доля его погружённой части составляет в точности $\\frac{900}{1000} = 0.9$ (или $90\\%$). Это позволяет решать качественные и устные задачи части B в ЕГЭ в одно действие.','#2eff8c','2026-06-14 09:27:00','2026-06-14 01:30:03',NULL);
